class Solution {
    public int[] pivotArray(int[] nums, int pivot) {
        int[] res = new int[nums.length];
        int less = 0, equal = 0, greater = nums.length - 1;
        for (int num : nums) {
            if (num < pivot) {
                res[less++] = num;
            } else if (num > pivot) {
                res[greater--] = num;
            } else {
                res[equal++] = num;
            }
        }
        return res;
    }
}
